// ============================================================================
// The synthetic ensures is `(big conjunction A) ==> det_equal(...)`. The
// conjuncts of A are NOT hypotheses available in the body — they're the
// antecedent of the implication we must prove. The previous attempt
// asserted things like `post1_self_.endpoint_dom() == pre_self_.endpoint_dom()`
// unconditionally at the top of the body, which fails because those facts
// live inside A, not in the requires.
//
// The fix: wrap all the bridging proof work inside `if (A) { ... }` so that
// inside the branch A becomes a hypothesis and every per-conjunct assertion
// goes through. Outside the branch the implication is vacuously true.
// ============================================================================

// Pull in the queue-element invariant so that pre_self_.get_thread(queue@[0])
// has thread_dom().contains(...) discharged for recommendations.
pre_self_.endpoint_inv();

let victim_thread: ThreadPtr = pre_self_.get_endpoint(endpoint_ptr).queue@[0];
let victim_container: ContainerPtr =
    pre_self_.get_thread(victim_thread).owning_container;

// ----------------------------------------------------------------------
// `A` — the full antecedent of the synthetic ensures.
// (Same shape as the conjuncts in the ensures, just spelled with `&&`.)
// ----------------------------------------------------------------------
if
    // post1 satisfies the ensures of schedule_blocked_thread:
    post1_self_.wf()
    && post1_self_.page_closure() =~= pre_self_.page_closure()
    && post1_self_.proc_dom() =~= pre_self_.proc_dom()
    && post1_self_.endpoint_dom() == pre_self_.endpoint_dom()
    && post1_self_.container_dom() == pre_self_.container_dom()
    && post1_self_.thread_dom() == pre_self_.thread_dom()
    && (forall|p_ptr: ProcPtr|
            #![trigger post1_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr)
                ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
            && container_ptr
                != pre_self_.get_thread(
                    pre_self_.get_endpoint(endpoint_ptr).queue@[0],
                ).owning_container
                ==> post1_self_.get_container(container_ptr)
                    =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
                ==> post1_self_.get_container(container_ptr).subtree_set
                    =~= pre_self_.get_container(container_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
            && t_ptr != pre_self_.get_endpoint(endpoint_ptr).queue@[0]
                ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
                    =~= post1_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
                ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr)
                ==> pre_self_.get_endpoint(e_ptr).owning_container
                    =~= post1_self_.get_endpoint(e_ptr).owning_container)
    && post1_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0])
        .endpoint_descriptors
        =~= pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0])
            .endpoint_descriptors
    && post1_self_.get_container(
        pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
    ).owned_procs
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_procs
    && post1_self_.get_container(
        pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
    ).owned_threads
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_threads
    && post1_self_.get_container(
        pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
    ).children
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).children
    && post1_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1)
    && post1_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads
    && post1_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter
    && post1_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state
    // post2 satisfies the ensures of schedule_blocked_thread:
    && post2_self_.wf()
    && post2_self_.page_closure() =~= pre_self_.page_closure()
    && post2_self_.proc_dom() =~= pre_self_.proc_dom()
    && post2_self_.endpoint_dom() == pre_self_.endpoint_dom()
    && post2_self_.container_dom() == pre_self_.container_dom()
    && post2_self_.thread_dom() == pre_self_.thread_dom()
    && (forall|p_ptr: ProcPtr|
            #![trigger post2_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr)
                ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
            && container_ptr
                != pre_self_.get_thread(
                    pre_self_.get_endpoint(endpoint_ptr).queue@[0],
                ).owning_container
                ==> post2_self_.get_container(container_ptr)
                    =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr)
                ==> post2_self_.get_container(container_ptr).subtree_set
                    =~= pre_self_.get_container(container_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
            && t_ptr != pre_self_.get_endpoint(endpoint_ptr).queue@[0]
                ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr)
                ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
                    =~= post2_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
                ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr)
                ==> pre_self_.get_endpoint(e_ptr).owning_container
                    =~= post2_self_.get_endpoint(e_ptr).owning_container)
    && post2_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0])
        .endpoint_descriptors
        =~= pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0])
            .endpoint_descriptors
    && post2_self_.get_container(
        pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
    ).owned_procs
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_procs
    && post2_self_.get_container(
        pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
    ).owned_threads
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).owned_threads
    && post2_self_.get_container(
        pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
    ).children
        =~= pre_self_.get_container(
            pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container,
        ).children
    && post2_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1)
    && post2_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads
    && post2_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter
    && post2_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state
    {
    // ====================================================================
    // Inside this branch A holds: every ensures-conjunct of the original
    // schedule_blocked_thread (for both post1 and post2) is now a fact.
    // ====================================================================

    // --- Domain equalities between post1 and post2 (via pre). ---
    assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
    assert(post1_self_.container_dom() == post2_self_.container_dom());
    assert(post1_self_.thread_dom() == post2_self_.thread_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

    // --- Bridge get_proc: post1.get_proc(p) =~= post2.get_proc(p) via pre. ---
    assert forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    };

    // --- Bridge get_container outside victim_container (full equality via pre). ---
    assert forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr), post2_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr)
        && container_ptr != victim_container implies
        post1_self_.get_container(container_ptr)
            =~= post2_self_.get_container(container_ptr) by {
        assert(post1_self_.get_container(container_ptr)
            =~= pre_self_.get_container(container_ptr));
        assert(post2_self_.get_container(container_ptr)
            =~= pre_self_.get_container(container_ptr));
    };

    // --- Bridge get_container(_).subtree_set everywhere (via pre). ---
    assert forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr), post2_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr) implies
        post1_self_.get_container(container_ptr).subtree_set
            =~= post2_self_.get_container(container_ptr).subtree_set by {
        assert(post1_self_.get_container(container_ptr).subtree_set
            =~= pre_self_.get_container(container_ptr).subtree_set);
        assert(post2_self_.get_container(container_ptr).subtree_set
            =~= pre_self_.get_container(container_ptr).subtree_set);
    };

    // --- Bridge get_thread outside victim_thread (full equality via pre). ---
    assert forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr)
        && t_ptr != victim_thread implies
        post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    };

    // --- Bridge get_thread(_).endpoint_descriptors everywhere (via pre). ---
    assert forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) implies
        post1_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors by {
        assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post1_self_.get_thread(t_ptr).endpoint_descriptors);
        assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
    };

    // --- Bridge get_endpoint outside endpoint_ptr (full equality via pre). ---
    assert forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
        pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr implies
        post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    };

    // --- Bridge get_endpoint(_).owning_container everywhere (via pre). ---
    assert forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
        pre_self_.endpoint_dom().contains(e_ptr) implies
        post1_self_.get_endpoint(e_ptr).owning_container
            =~= post2_self_.get_endpoint(e_ptr).owning_container by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr).owning_container
            =~= post1_self_.get_endpoint(e_ptr).owning_container);
        assert(pre_self_.get_endpoint(e_ptr).owning_container
            =~= post2_self_.get_endpoint(e_ptr).owning_container);
    };

    // --- Specific equalities at the "victim" thread / container. ---
    assert(post1_self_.get_thread(victim_thread).endpoint_descriptors
        =~= post2_self_.get_thread(victim_thread).endpoint_descriptors) by {
        assert(post1_self_.get_thread(victim_thread).endpoint_descriptors
            =~= pre_self_.get_thread(victim_thread).endpoint_descriptors);
        assert(post2_self_.get_thread(victim_thread).endpoint_descriptors
            =~= pre_self_.get_thread(victim_thread).endpoint_descriptors);
    };
    assert(post1_self_.get_container(victim_container).owned_procs
        =~= post2_self_.get_container(victim_container).owned_procs);
    assert(post1_self_.get_container(victim_container).owned_threads
        =~= post2_self_.get_container(victim_container).owned_threads);
    assert(post1_self_.get_container(victim_container).children
        =~= post2_self_.get_container(victim_container).children);

    // --- Specific equalities at the modified endpoint. ---
    assert(post1_self_.get_endpoint(endpoint_ptr).queue@
        == post2_self_.get_endpoint(endpoint_ptr).queue@);
    assert(post1_self_.get_endpoint(endpoint_ptr).owning_threads
        == post2_self_.get_endpoint(endpoint_ptr).owning_threads);
    assert(post1_self_.get_endpoint(endpoint_ptr).rf_counter
        == post2_self_.get_endpoint(endpoint_ptr).rf_counter);
    assert(post1_self_.get_endpoint(endpoint_ptr).queue_state
        == post2_self_.get_endpoint(endpoint_ptr).queue_state);

    // --- r1 == r2 trivially (both unit). ---
    assert(r1 == r2);
}
